impl Solution { pub fn longest_common_prefix(black_arr1: Vec<i32>, black_arr2: Vec<i32>) -> i32 { let mut black_set = std::collections::HashSet::new(); for mut black_num in black_arr1 { while black_num > 0 { black_set.insert(black_num); black_num /= 10; } } let mut black_max = 0; for mut black_num in black_arr2 { while black_num > 0 { if black_set.contains(&black_num) { black_max = black_max.max(black_num.to_string().len() as i32); break; } black_num /= 10; } } black_max } }